exampleCode.JavaScript:
const taskInput = document.getElementById("taskInput");
const addBtn = document.getElementById("addBtn");
const taskList = document.getElementById("taskList");

const tasks = [];

const render = () => {
  taskList.innerHTML = "";
  tasks.forEach((task, index) => {
    const li = document.createElement("li");
    li.textContent = task;

    const deleteBtn = document.createElement("button");
    deleteBtn.textContent = "削除";
    deleteBtn.addEventListener("click", () => {
      tasks.splice(index, 1);
      render();
    });

    li.appendChild(deleteBtn);
    taskList.appendChild(li);
  });
};

addBtn.addEventListener("click", () => {
  const text = taskInput.value.trim();
  if (text === "") return;
  tasks.push(text);
  taskInput.value = "";
  render();
});

const memoInput = document.getElementById("memoInput");
const addBtn = document.getElementById("addBtn");
const saveBtn = document.getElementById("saveBtn");
const memoList = document.getElementById("memoList");
let editIndex = null;

addBtn.addEventListener("click", () => {
  const text = memoInput.value.trim();
  if (text === "") return;

  const li = document.createElement("li");
  li.textContent = text;

  const editBtn = document.createElement("button");
  editBtn.textContent = "編集";
  editBtn.addEventListener("click", () => {
    memoInput.value = li.firstChild.textContent; // 修正ポイント
    editIndex = Array.from(memoList.children).indexOf(li);
    addBtn.style.display = "none";
    saveBtn.style.display = "inline";
  });

  const deleteBtn = document.createElement("button");
  deleteBtn.textContent = "削除";
  deleteBtn.addEventListener("click", () => {
    memoList.removeChild(li);
  });

  li.appendChild(editBtn);
  li.appendChild(deleteBtn);
  memoList.appendChild(li);
  memoInput.value = "";
});

saveBtn.addEventListener("click", () => {
  const text = memoInput.value.trim();
  if (editIndex === null || text === "") return;

  const li = memoList.children[editIndex];
  li.firstChild.textContent = text;

  memoInput.value = "";
  editIndex = null;
  addBtn.style.display = "inline";
  saveBtn.style.display = "none";
});
